import{_ as t,o as a,c as n,ag as r}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Je eerste factuur","description":"","frontmatter":{},"headers":[],"relativePath":"nl/getting-started/first-invoice.md","filePath":"nl/getting-started/first-invoice.md"}'),i={name:"nl/getting-started/first-invoice.md"};function l(o,e,s,u,d,g){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="je-eerste-factuur" tabindex="-1">Je eerste factuur <a class="header-anchor" href="#je-eerste-factuur" aria-label="Permalink to &quot;Je eerste factuur&quot;">​</a></h1><p>Deze gids helpt je stap voor stap bij het maken en versturen van je eerste factuur in MyCompanyDesk.</p><h2 id="voordat-je-begint" tabindex="-1">Voordat je begint <a class="header-anchor" href="#voordat-je-begint" aria-label="Permalink to &quot;Voordat je begint&quot;">​</a></h2><p>Zorg dat je het volgende hebt gedaan:</p><ul><li><a href="/nl/getting-started/company-setup">Je bedrijfsinformatie ingesteld</a> (naam, adres, IBAN)</li><li>Ten minste een klant om te factureren (je kunt er een aanmaken tijdens het proces)</li></ul><h2 id="een-factuur-maken" tabindex="-1">Een factuur maken <a class="header-anchor" href="#een-factuur-maken" aria-label="Permalink to &quot;Een factuur maken&quot;">​</a></h2><ol><li>Navigeer naar <strong>Facturen</strong> in de zijbalk</li><li>Klik op de knop <strong>Nieuwe factuur</strong> (of gebruik de <strong>+</strong> zwevende knop op mobiel)</li><li>Vul het factuurformulier in:</li></ol><h3 id="selecteer-een-klant" tabindex="-1">Selecteer een klant <a class="header-anchor" href="#selecteer-een-klant" aria-label="Permalink to &quot;Selecteer een klant&quot;">​</a></h3><p>Begin met het typen van de klantnaam. Als de klant al bestaat, selecteer deze dan uit de dropdown. Zo niet, klik dan op <strong>Nieuwe klant aanmaken</strong> om er direct een toe te voegen.</p><h3 id="regelitems-toevoegen" tabindex="-1">Regelitems toevoegen <a class="header-anchor" href="#regelitems-toevoegen" aria-label="Permalink to &quot;Regelitems toevoegen&quot;">​</a></h3><p>Elk regelitem bevat:</p><ul><li><strong>Omschrijving</strong> — Waarvoor je factureert</li><li><strong>Aantal</strong> — Aantal eenheden</li><li><strong>Eenheidsprijs</strong> — Prijs per eenheid</li><li><strong>BTW-tarief</strong> — Toepasselijk BTW-percentage (0%, 9%, 21%, etc.)</li></ul><p>Klik op <strong>Item toevoegen</strong> om meer regelitems toe te voegen. Het totaal wordt automatisch berekend inclusief BTW.</p><h3 id="factuurgegevens-instellen" tabindex="-1">Factuurgegevens instellen <a class="header-anchor" href="#factuurgegevens-instellen" aria-label="Permalink to &quot;Factuurgegevens instellen&quot;">​</a></h3><ul><li><strong>Factuurnummer</strong> — Automatisch gegenereerd op basis van je nummeringsinstellingen</li><li><strong>Factuurdatum</strong> — Standaard vandaag</li><li><strong>Vervaldatum</strong> — Berekend op basis van je standaard betalingstermijn (aanpasbaar)</li><li><strong>Notities</strong> — Optionele notities die op de factuur verschijnen</li></ul><h3 id="opslaan" tabindex="-1">Opslaan <a class="header-anchor" href="#opslaan" aria-label="Permalink to &quot;Opslaan&quot;">​</a></h3><p>Klik op <strong>Opslaan</strong> om de factuur aan te maken als <strong>concept</strong>. Je kunt alles nog bewerken voor het versturen.</p><h2 id="factuur-bekijken" tabindex="-1">Factuur bekijken <a class="header-anchor" href="#factuur-bekijken" aria-label="Permalink to &quot;Factuur bekijken&quot;">​</a></h2><p>Bekijk voor het versturen hoe de PDF eruitziet:</p><ol><li>Open de factuurdetailpagina</li><li>Klik op <strong>Voorbeeld</strong> om de gegenereerde PDF te bekijken</li><li>Controleer of alle informatie klopt — bedrijfsgegevens, klantinfo, regelitems, totalen</li></ol><h2 id="factuur-versturen" tabindex="-1">Factuur versturen <a class="header-anchor" href="#factuur-versturen" aria-label="Permalink to &quot;Factuur versturen&quot;">​</a></h2><p>Wanneer je klaar bent om te versturen:</p><ol><li>Klik op <strong>Versturen</strong> op de factuurdetailpagina</li><li>Bekijk de e-mail die naar je klant wordt gestuurd: <ul><li>Onderwerpregel (aanpasbaar)</li><li>E-mailtekst (gebaseerd op je e-mailsjabloon)</li><li>PDF-bijlage</li><li>Betaallink (indien ingeschakeld)</li></ul></li><li>Klik op <strong>Versturen</strong> om de factuur te bezorgen</li></ol><p>De factuurstatus verandert van <strong>Concept</strong> naar <strong>Verzonden</strong>.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Je kunt je e-mailsjablonen aanpassen in <strong>Instellingen &gt; E-mail</strong>. Sjablonen ondersteunen je huisstijl en kunnen per taal worden ingesteld.</p></div><h2 id="betaling-bijhouden" tabindex="-1">Betaling bijhouden <a class="header-anchor" href="#betaling-bijhouden" aria-label="Permalink to &quot;Betaling bijhouden&quot;">​</a></h2><p>Na het versturen verschijnt de factuur in je <strong>Verzonden</strong> of <strong>Achterstallig</strong> overzichten. Wanneer de klant betaalt:</p><ul><li>Als de klant via de <strong>betaallink</strong> betaalt, wordt de factuur automatisch als betaald gemarkeerd</li><li>Voor bankoverschrijvingen klik je op <strong>Markeer als betaald</strong> op de factuur om de betaling handmatig te registreren</li></ul><h2 id="factuurstatussen" tabindex="-1">Factuurstatussen <a class="header-anchor" href="#factuurstatussen" aria-label="Permalink to &quot;Factuurstatussen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Beschrijving</th></tr></thead><tbody><tr><td><strong>Concept</strong></td><td>Aangemaakt maar nog niet verstuurd. Volledig bewerkbaar.</td></tr><tr><td><strong>Verzonden</strong></td><td>Bezorgd bij de klant. Wacht op betaling.</td></tr><tr><td><strong>Achterstallig</strong></td><td>Voorbij de vervaldatum en nog niet betaald.</td></tr><tr><td><strong>Betaald</strong></td><td>Betaling ontvangen en bevestigd.</td></tr><tr><td><strong>Geannuleerd</strong></td><td>Factuur is geannuleerd. Geen betaling verwacht.</td></tr></tbody></table><h2 id="snel-toevoegen" tabindex="-1">Snel toevoegen <a class="header-anchor" href="#snel-toevoegen" aria-label="Permalink to &quot;Snel toevoegen&quot;">​</a></h2><p>Voor snellere factuuraanmaak gebruik je <strong>Snel toevoegen</strong>:</p><ol><li>Klik op het snel-toevoegen-icoon op de facturenlijstpagina</li><li>Selecteer een klant</li><li>Voeg items toe (of gebruik een opgeslagen sjabloon)</li><li>Sla op en verstuur optioneel direct</li></ol><p>Snel toevoegen is ideaal voor routinefacturen waarbij je regelmatig vergelijkbare items factureert.</p><h2 id="sjablonen-gebruiken" tabindex="-1">Sjablonen gebruiken <a class="header-anchor" href="#sjablonen-gebruiken" aria-label="Permalink to &quot;Sjablonen gebruiken&quot;">​</a></h2><p>Bespaar tijd met factuursjablonen:</p><ol><li>Maak een factuur met je meestgebruikte regelitems</li><li>Klik op <strong>Opslaan als sjabloon</strong></li><li>De volgende keer begin je een nieuwe factuur vanuit het sjabloon — alle items zijn vooraf ingevuld</li></ol><h2 id="volgende-stappen" tabindex="-1">Volgende stappen <a class="header-anchor" href="#volgende-stappen" aria-label="Permalink to &quot;Volgende stappen&quot;">​</a></h2><p>Gefeliciteerd met het versturen van je eerste factuur! Ontdek meer functies:</p><ul><li><a href="/nl/features/expenses">Uitgaven bijhouden</a></li><li><a href="/nl/features/quotes">Offertes maken</a> voor potentieel werk</li><li><a href="/nl/features/recurring-invoices">Terugkerende facturen instellen</a> voor regelmatige facturatie</li><li><a href="/nl/features/reports">Rapportages bekijken</a> om je financien te begrijpen</li></ul>',40)])])}const p=t(i,[["render",l]]);export{h as __pageData,p as default};
